import React from "react";
import { LogOut } from "lucide-react";
import { HeaderProps } from "../types";

/**
 * Componente Header da aplicação
 * Exibe o título da aplicação e botão de logout
 * 
 * @param onLogout - Função callback para realizar logout
 */
const Header = ({ onLogout }: HeaderProps) => {
  return (
    <header className="flex justify-between items-center p-4 border-b bg-white shadow-sm">
      {/* Título da aplicação */}
      <h1 className="text-2xl font-bold text-gray-800">enContact</h1>
      
      {/* Botão de logout com ícone */}
      <button
        onClick={onLogout}
        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-red-600 hover:text-red-800 hover:bg-red-50 rounded-md transition-colors duration-200"
        title="Sair do sistema"
      >
        <LogOut size={16} />
        <span>Sair</span>
      </button>
    </header>
  );
};

export default Header;
